input.command:
awk -F: '$2 != "*" && $2 != "!" && $2 != "" {
  hash=$2
  if (match(hash, /^\$([0-9a-z]+)\$/)) {
    algo_id=substr(hash, 2, RLENGTH-3)
    if (algo_id == "1") algorithm="MD5"
    else if (algo_id == "2a" || algo_id == "2b" || algo_id == "2x" || algo_id == "2y") algorithm="bcrypt"
    else if (algo_id == "5") algorithm="SHA-256"
    else if (algo_id == "6") algorithm="SHA-512"
    else algorithm="Unknown ($" algo_id "$)"
  } else if (hash ~ /^[a-zA-Z0-9.\/]+$/ && length(hash) == 13) {
    algorithm="DES (weak)"
  } else {
    algorithm="Unknown format"
  }
  printf "%-20s %s\n", $1, algorithm
}' /etc/shadow | sort

awk -F: '
BEGIN {print "Account Name         Password Hash Type      Status"}
BEGIN {print "==================== ======================== =============="}
{
  username=$1
  hash=$2

  if (hash == "*" || hash == "!") {
    status="Locked/Disabled"
    hashtype="N/A"
  } else if (hash == "") {
    status="No Password"
    hashtype="N/A"
  } else if (match(hash, /^\$([0-9a-z]+)\$/)) {
    algo_id=substr(hash, 2, RLENGTH-3)
    if (algo_id == "1") hashtype="MD5"
    else if (algo_id == "2a" || algo_id == "2b" || algo_id == "2x" || algo_id == "2y") hashtype="bcrypt"
    else if (algo_id == "5") hashtype="SHA-256"
    else if (algo_id == "6") hashtype="SHA-512"
    else hashtype="Unknown ($" algo_id "$)"
    status="Active"
  } else if (hash ~ /^[a-zA-Z0-9.\/]{13}$/) {
    hashtype="DES (legacy)"
    status="Active"
  } else {
    hashtype="Unrecognized"
    status="Unknown"
  }

  printf "%-20s %-24s %s\n", username, hashtype, status
}' /etc/shadow | sort

cat /etc/shadow | awk -F: '
BEGIN {
  print ""
  print "==========================================================================="
  print "PASSWORD HASH ALGORITHM REPORT - /etc/shadow"
  print "==========================================================================="
  print ""
  printf "%-20s %-20s %s\n", "Account", "Hash Algorithm", "Status"
  print "---------------------------------------------------------------------------"
}
{
  username=$1
  hash=$2

  if (hash == "*") {
    algorithm="None (account locked)"
    status="LOCKED"
  } else if (hash == "!") {
    algorithm="None (password locked)"
    status="LOCKED"
  } else if (hash == "") {
    algorithm="None (no password)"
    status="NO PASSWORD"
  } else if (match(hash, /^\$6\$/)) {
    algorithm="SHA-512"
    status="✓ STRONG"
  } else if (match(hash, /^\$5\$/)) {
    algorithm="SHA-256"
    status="✓ ACCEPTABLE"
  } else if (match(hash, /^\$2[aby]\$/)) {
    algorithm="bcrypt"
    status="✓ STRONG"
  } else if (match(hash, /^\$1\$/)) {
    algorithm="MD5"
    status="✗ WEAK"
  } else if (length(hash) == 13 && hash ~ /^[a-zA-Z0-9.\/]+$/) {
    algorithm="DES"
    status="✗ VERY WEAK"
  } else {
    algorithm="Unknown format"
    status="?"
  }

  printf "%-20s %-20s %s\n", username, algorithm, status
}
END {
  print "---------------------------------------------------------------------------"
  print ""
  print "KEY:"
  print "  ✓ STRONG    - Cryptographically secure for modern use"
  print "  ✓ ACCEPTABLE - Adequate for most purposes"
  print "  ✗ WEAK      - Not recommended for new systems"
  print "  ✗ VERY WEAK - Should be updated immediately"
  print ""
}' | sort -k1,1
